create or replace function public.record_trusted_workflow_event(p_instance_id uuid,p_kind text,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; begin if auth.role()<>'service_role' then raise exception 'Trusted workflow events require server role'; end if; select * into i from public.workflow_instances where id=p_instance_id for update; if not found then raise exception 'Instance not found'; end if; insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,metadata,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,p_kind,p_action,p_metadata,auth.uid()); end $$;
create or replace function public.start_workflow_instance(p_version_id uuid,p_source_type text,p_source_id uuid) returns uuid language plpgsql security definer set search_path=public as $$ declare v public.workflow_versions%rowtype; initial_state text; new_id uuid; begin select * into v from public.workflow_versions where id=p_version_id for update; if not found or v.status<>'published' or not public.can_workflow('workflows.start',v.tenant_id,v.organization_id,v.facility_id) or not public.validate_workflow_definition(v.definition) then raise exception 'Workflow start denied'; end if; select s->>'key' into initial_state from jsonb_array_elements(v.definition->'states') s where coalesce((s->>'initial')::boolean,false); if initial_state is null then raise exception 'Workflow initial state missing'; end if; if exists(select 1 from public.workflow_instances where workflow_version_id=v.id and source_type=p_source_type and source_id=p_source_id and state_key not in ('closed','cancelled')) then raise exception 'Active workflow already exists'; end if; insert into public.workflow_instances(workflow_version_id,tenant_id,organization_id,facility_id,source_type,source_id,state_key,created_by,updated_by) values(v.id,v.tenant_id,v.organization_id,v.facility_id,p_source_type,p_source_id,initial_state,auth.uid(),auth.uid()) returning id into new_id; insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,created_by) values(new_id,v.tenant_id,v.organization_id,v.facility_id,'system','instance.started',auth.uid()); return new_id; end $$;
create or replace function public.transition_workflow_instance(p_instance_id uuid,p_to text,p_reason text default null,p_comment text default null,p_fields jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; v public.workflow_versions%rowtype; t jsonb; required_permission text; begin select * into i from public.workflow_instances where id=p_instance_id for update; select * into v from public.workflow_versions where id=i.workflow_version_id and status='published'; select value into t from jsonb_array_elements(v.definition->'transitions') where value->>'from'=i.state_key and value->>'to'=p_to; if i.locked or t is null then raise exception 'Invalid or locked workflow transition'; end if; required_permission:=t->>'requiredPermission'; if required_permission is not null and not public.can_workflow(required_permission,i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Transition permission denied'; end if; if coalesce((t->>'requiresReason')::boolean,false) and coalesce(trim(p_reason),'')='' then raise exception 'Transition reason required'; end if; if coalesce((t->>'requiresComment')::boolean,false) and coalesce(trim(p_comment),'')='' then raise exception 'Transition comment required'; end if; if exists(select 1 from jsonb_array_elements_text(coalesce(t->'requiredFields','[]'::jsonb)) f where p_fields->>f is null or p_fields->>f='') then raise exception 'Transition required field missing'; end if; update public.workflow_instances set state_key=p_to,revision=revision+1,updated_at=now(),updated_by=auth.uid() where id=i.id; insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,metadata,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,'transition','instance.transition',jsonb_build_object('from',i.state_key,'to',p_to),auth.uid()); end $$;
create or replace function public.request_workflow_approval(p_instance_id uuid,p_mode text,p_approver_id uuid,p_distinct_from uuid default null) returns uuid language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; id uuid; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not public.can_workflow('workflows.approve',i.tenant_id,i.organization_id,i.facility_id) or p_mode not in ('single','sequential','parallel','any_one','unanimous') then raise exception 'Approval request denied'; end if; insert into public.workflow_approvals(instance_id,tenant_id,organization_id,facility_id,sequence,mode,approver_id,distinct_from_id,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,1,p_mode,p_approver_id,p_distinct_from,auth.uid()) returning id into id; return id; end $$;
create or replace function public.approve_workflow_request(p_approval_id uuid,p_comment text default null) returns void language plpgsql security definer set search_path=public as $$ declare a public.workflow_approvals%rowtype; begin select * into a from public.workflow_approvals where id=p_approval_id for update; if a.status<>'requested' or a.approver_id<>auth.uid() or a.distinct_from_id=auth.uid() then raise exception 'Approval denied'; end if; update public.workflow_approvals set status='approved',comment=p_comment where id=a.id; insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,created_by) values(a.instance_id,a.tenant_id,a.organization_id,a.facility_id,'approval','approval.approved',auth.uid()); end $$;
create or replace function public.create_workflow_task(p_instance_id uuid,p_title_en text,p_assignee_id uuid default null) returns uuid language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; id uuid; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not public.can_workflow('workflows.manage_tasks',i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Task permission denied'; end if; insert into public.workflow_tasks(instance_id,tenant_id,organization_id,facility_id,title_en,assignee_id,created_by,updated_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,p_title_en,p_assignee_id,auth.uid(),auth.uid()) returning id into id; return id; end $$;
revoke all on function public.record_trusted_workflow_event(uuid,text,text,jsonb) from public,anon,authenticated; revoke all on function public.start_workflow_instance(uuid,text,uuid),public.transition_workflow_instance(uuid,text,text,text,jsonb),public.request_workflow_approval(uuid,text,uuid,uuid),public.approve_workflow_request(uuid,text),public.create_workflow_task(uuid,text,uuid) from public,anon; grant execute on function public.start_workflow_instance(uuid,text,uuid),public.transition_workflow_instance(uuid,text,text,text,jsonb),public.request_workflow_approval(uuid,text,uuid,uuid),public.approve_workflow_request(uuid,text),public.create_workflow_task(uuid,text,uuid) to authenticated;
